--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ ... @@
-function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string, offsetY: number, wallHeight: number) {
-  // existing implementation
-}
+function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, baseColor: string, offsetY: number, wallHeight: number) {
+  const brickWidth = 16;
+  const brickHeight = 8;
+  const mortarColor = 'rgba(255,255,255,0.2)';
+  const rows = Math.ceil(h / brickHeight);
+  const cols = Math.ceil(w / brickWidth);
+
+  // Parse baseColor to RGB
+  function parseRGB(c: string) {
+    const m = c.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
+    return m ? [parseInt(m[1]), parseInt(m[2]), parseInt(m[3])] : [128, 128, 128];
+  }
+
+  // Clamp color channel
+  function clamp(v: number) {
+    return Math.min(255, Math.max(0, v));
+  }
+
+  // Shade color by amount (-10 to +10)
+  function shadeColor(rgb: number[], amount: number) {
+    return `rgb(${clamp(rgb[0] + amount)},${clamp(rgb[1] + amount)},${clamp(rgb[2] + amount)})`;
+  }
+
+  const baseRGB = parseRGB(baseColor);
+
+  // Draw bricks with color variation and mortar lines
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      // Offset every other row for brick pattern
+      const xOff = (row % 2) * (brickWidth / 2);
+      const bx = x + col * brickWidth - xOff;
+      const by = y + row * brickHeight + offsetY;
+
+      // Skip bricks partially outside wall bounds
+      if (bx + brickWidth < x || bx > x + w) continue;
+
+      // Random shade variation ±10
+      const shade = (Math.floor((bx + by) * 7) % 21) - 10;
+      const brickColor = shadeColor(baseRGB, shade);
+
+      // Draw brick
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(bx, by, brickWidth, brickHeight);
+    }
+  }
+
+  // Draw mortar lines (1px lighter lines in brick pattern)
+  ctx.strokeStyle = mortarColor;
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  // Horizontal mortar lines
+  for (let row = 0; row <= rows; row++) {
+    const yLine = y + row * brickHeight + offsetY + 0.5;
+    ctx.moveTo(x, yLine);
+    ctx.lineTo(x + w, yLine);
+  }
+  // Vertical mortar lines with offset every other row
+  for (let col = 0; col <= cols; col++) {
+    for (let row = 0; row < rows; row++) {
+      const xOff = (row % 2) * (brickWidth / 2);
+      const xLine = x + col * brickWidth - xOff + 0.5;
+      const yStart = y + row * brickHeight + offsetY;
+      const yEnd = yStart + brickHeight;
+      if (xLine >= x && xLine <= x + w) {
+        ctx.moveTo(xLine, yStart);
+        ctx.lineTo(xLine, yEnd);
+      }
+    }
+  }
+  ctx.stroke();
+
+  // Shadow gradient (darker at bottom, lighter at top)
+  const grad = ctx.createLinearGradient(x, y + offsetY, x, y + offsetY + h);
+  grad.addColorStop(0, 'rgba(255,255,255,0.15)');
+  grad.addColorStop(1, 'rgba(0,0,0,0.3)');
+  ctx.fillStyle = grad;
+  ctx.fillRect(x, y + offsetY, w, h);
+
+  // Subtle highlight line at top edge
+  ctx.strokeStyle = 'rgba(255,255,255,0.3)';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(x, y + offsetY + 0.5);
+  ctx.lineTo(x + w, y + offsetY + 0.5);
+  ctx.stroke();
+}
